"use strict";parserFactory.register("ncode.syosetu.com",()=>new SyosetuParser),parserFactory.register("novel18.syosetu.com",()=>new SyosetuParser);class SyosetuParser extends Parser{constructor(){super(),this.infoPageDom=null}async getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,this.extractPartialChapterList,this.getUrlsOfTocPages,t)}getUrlsOfTocPages(e){let t=e.querySelector("a.c-pager__item--last"),r=[];if(t){const e=parseInt(t.href.split("?p=")[1]),l=t.href.substring(0,t.href.lastIndexOf("?p="));for(let t=2;t<=e;t++)r.push(`${l}?p=${t}`)}return r}extractPartialChapterList(e){let t=e.querySelector("div.index_box")||e.querySelector("div.p-eplist");if(!t)return[];let r=[],l=null;for(let e of t.querySelectorAll(".p-eplist__chapter-title, a")){if(e.classList?.contains("p-eplist__chapter-title")){l=e.textContent.trim();continue}let t=util.hyperLinkToChapter(e);l&&(t.newArc=l,l=null),r.push(t)}return r}findContent(e){return e.querySelector("div.p-novel__body")}preprocessRawDom(e){let t=this.findContent(e);this.tagAuthorNotesBySelector(t,"div.p-novel__text--preface, div.p-novel__text--afterword")}extractTitleImpl(e){return e.querySelector(".p-novel__title")}extractAuthor(e){const t=e.querySelector("div.p-novel__author");if(t){const e=t.textContent.trim().replace(/^作者：/,"");return t.querySelector("a")?.textContent.trim()||e}return super.extractAuthor(e)}findChapterTitle(e){let t=e.querySelector(".p-novel__title");return null===t?null:t.textContent}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("h1.p-novel__title, #novel_ex")]}extractDescription(e){return e.querySelector(".p-novel__summary").textContent.trim()}}